CREATE TABLE "Categories" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Nom" character varying(100) NOT NULL,
    CONSTRAINT "PK_Categories" PRIMARY KEY ("ID")
);


CREATE TABLE "Clients" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "NumeroClient" character varying(20) NOT NULL,
    "Nom" character varying(100) NOT NULL,
    "Contact" character varying(100),
    "CIN" character varying(100) NOT NULL,
    "NomSociete" character varying(100) NOT NULL,
    "userID" integer NOT NULL,
    "DateCreation" timestamp with time zone NOT NULL,
    "DateModification" timestamp with time zone,
    CONSTRAINT "PK_Clients" PRIMARY KEY ("ID")
);


CREATE TABLE "DepenseCategories" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Nom" character varying(100) NOT NULL,
    "Description" character varying(500),
    "IsActive" boolean NOT NULL,
    "CreePar" character varying(50),
    "DateCreation" timestamp with time zone,
    "ModifiePar" character varying(50),
    "DateModification" timestamp with time zone,
    CONSTRAINT "PK_DepenseCategories" PRIMARY KEY ("ID")
);


CREATE TABLE "Depenses" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Numero" character varying(20),
    "Date" date,
    "Categorie" character varying(100),
    "Montant" numeric(10,2),
    "Description" character varying(500),
    "CreePar" character varying(50),
    "DateCreation" timestamp with time zone,
    "ModifiePar" character varying(50),
    "DateModification" timestamp with time zone,
    CONSTRAINT "PK_Depenses" PRIMARY KEY ("ID")
);


CREATE TABLE "Employes" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Nom" character varying(50) NOT NULL,
    "Prenom" character varying(50) NOT NULL,
    "CIN" character varying(20) NOT NULL,
