    "DateCreation" timestamp with time zone,
    "ModifiePar" integer,
    "DateModification" timestamp with time zone,
    CONSTRAINT "PK_Fournisseurs" PRIMARY KEY ("ID")
);


CREATE TABLE "IndicateursFinanciers" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
