    "UpdatedAt" timestamp with time zone NOT NULL,
    "CanManageUsers" boolean NOT NULL,
    "CanManageProducts" boolean NOT NULL,
    "CanViewReports" boolean NOT NULL,
    "CanManageSettings" boolean NOT NULL,
    "CanManageSales" boolean NOT NULL,
    "CanManagePromotions" boolean NOT NULL,
    "CanManageCustomers" boolean NOT NULL,
    "CanManageSuppliers" boolean NOT NULL,
    "CanManageCategories" boolean NOT NULL,
    "ShowAcceuil" boolean NOT NULL,
    "ShowTableauDeBord" boolean NOT NULL,
    "ShowVente" boolean NOT NULL,
    "EditLivreur" boolean NOT NULL,
    "AddAchat" boolean NOT NULL,
    "EditCiternes" boolean NOT NULL,
