    "Statut" character varying(50) NOT NULL,
    "CompteurElectroniqueActuel" numeric(18,3),
    "CompteurMecaniqueActuel" numeric(18,3),
    "ReservoirAssocieID" integer,
    "AjoutePar" integer,
    "DateCreation" timestamp with time zone,
    "ModifiePar" integer,
    "DateModification" timestamp with time zone,
    CONSTRAINT "PK_Pompes" PRIMARY KEY ("ID"),
    CONSTRAINT "FK_Pompes_Reservoirs_ReservoirAssocieID" FOREIGN KEY ("ReservoirAssocieID") REFERENCES "Reservoirs" ("ID")
);


CREATE TABLE "ReservoirCalibrations" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "ReservoirID" integer NOT NULL,
    "HauteurCm" numeric(6,2) NOT NULL,
    "VolumeLitres" numeric(12,2) NOT NULL,
    CONSTRAINT "PK_ReservoirCalibrations" PRIMARY KEY ("ID"),
    CONSTRAINT "FK_ReservoirCalibrations_Reservoirs_ReservoirID" FOREIGN KEY ("ReservoirID") REFERENCES "Reservoirs" ("ID") ON DELETE CASCADE
);


CREATE TABLE "Achats" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Numero" character varying(20),
    "Date" date NOT NULL,
    "FournisseurID" integer,
    "ProduitID" integer,
    "Quantite" integer,
    "Cout" numeric(10,2),
    "PrixAchatUnitaire" numeric(10,2),
    "ChauffeurID" integer,
    "CamionID" integer,
    "LivraisonDefectueuse" boolean,
    "AjoutePar" integer,
    "DateCreation" timestamp with time zone,
    "ModifiePar" integer,
    "DateModification" timestamp with time zone,
    CONSTRAINT "PK_Achats" PRIMARY KEY ("ID"),
    CONSTRAINT "FK_Achats_Camions_CamionID" FOREIGN KEY ("CamionID") REFERENCES "Camions" ("ID"),
    CONSTRAINT "FK_Achats_Chauffeurs_ChauffeurID" FOREIGN KEY ("ChauffeurID") REFERENCES "Chauffeurs" ("ID"),
    CONSTRAINT "FK_Achats_Fournisseurs_FournisseurID" FOREIGN KEY ("FournisseurID") REFERENCES "Fournisseurs" ("ID"),
    CONSTRAINT "FK_Achats_Produits_ProduitID" FOREIGN KEY ("ProduitID") REFERENCES "Produits" ("ID")
);


CREATE TABLE "PeriodeDetails" (
    "PeriodeDetailID" integer GENERATED BY DEFAULT AS IDENTITY,
    "PeriodeID" integer NOT NULL,
    "PompeID" integer NOT NULL,
    "ReservoirID" integer NOT NULL,
    "ProduitID" integer NOT NULL,
    "PrixCarburant" numeric(10,2) NOT NULL,
    "CompteurElectroniqueDebut" numeric NOT NULL,
    "CompteurElectroniqueFinal" numeric NOT NULL,
    "CompteurMecaniqueDebut" numeric NOT NULL,
    "CompteurMecaniqueFinal" numeric NOT NULL,
    CONSTRAINT "PK_PeriodeDetails" PRIMARY KEY ("PeriodeDetailID"),
    CONSTRAINT "FK_PeriodeDetails_Periodes_PeriodeID" FOREIGN KEY ("PeriodeID") REFERENCES "Periodes" ("PeriodeID") ON DELETE CASCADE,
    CONSTRAINT "FK_PeriodeDetails_Pompes_PompeID" FOREIGN KEY ("PompeID") REFERENCES "Pompes" ("ID") ON DELETE CASCADE,
    CONSTRAINT "FK_PeriodeDetails_Produits_ProduitID" FOREIGN KEY ("ProduitID") REFERENCES "Produits" ("ID") ON DELETE CASCADE,
    CONSTRAINT "FK_PeriodeDetails_Reservoirs_ReservoirID" FOREIGN KEY ("ReservoirID") REFERENCES "Reservoirs" ("ID") ON DELETE CASCADE
);


CREATE TABLE "AchatAllocations" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "AchatID" integer NOT NULL,
    "ReservoirID" integer NOT NULL,
    "QuantiteAllouee" numeric(10,2) NOT NULL,
    "DateAllocation" timestamp with time zone NOT NULL,
    "Notes" character varying(500),
    "Statut" character varying(50) NOT NULL,
    "UtilisateurAllocation" character varying(100),
    CONSTRAINT "PK_AchatAllocations" PRIMARY KEY ("ID"),
    CONSTRAINT "FK_AchatAllocations_Achats_AchatID" FOREIGN KEY ("AchatID") REFERENCES "Achats" ("ID") ON DELETE CASCADE,
    CONSTRAINT "FK_AchatAllocations_Reservoirs_ReservoirID" FOREIGN KEY ("ReservoirID") REFERENCES "Reservoirs" ("ID") ON DELETE CASCADE
);


CREATE TABLE "StockLots" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "Type" integer NOT NULL DEFAULT 1,
    "AchatID" integer,
    "ReservoirID" integer NOT NULL,
    "ProduitID" integer NOT NULL,
    "QuantiteInitiale" numeric(12,3) NOT NULL,
    "QuantiteDisponible" numeric(12,3) NOT NULL,
    "PrixAchat" numeric(10,2) NOT NULL,
    "DateEntree" timestamp with time zone NOT NULL,
    "Statut" character varying(20) NOT NULL,
    "Notes" character varying(500),
    CONSTRAINT "PK_StockLots" PRIMARY KEY ("ID"),
    CONSTRAINT "CK_StockLots_AchatID_Type_Consistency" CHECK (("Type" = 1 AND "AchatID" IS NOT NULL) OR ("Type" != 1 AND "AchatID" IS NULL)),
    CONSTRAINT "CK_StockLots_PrixAchat_NonNegative" CHECK ("PrixAchat" >= 0),
    CONSTRAINT "CK_StockLots_QuantiteDisponible_Bounds" CHECK ("QuantiteDisponible" >= 0 AND "QuantiteDisponible" <= "QuantiteInitiale"),
    CONSTRAINT "CK_StockLots_QuantiteInitiale_Positive" CHECK ("QuantiteInitiale" > 0),
    CONSTRAINT "FK_StockLots_Achats_AchatID" FOREIGN KEY ("AchatID") REFERENCES "Achats" ("ID") ON DELETE RESTRICT,
    CONSTRAINT "FK_StockLots_Produits_ProduitID" FOREIGN KEY ("ProduitID") REFERENCES "Produits" ("ID") ON DELETE RESTRICT,
    CONSTRAINT "FK_StockLots_Reservoirs_ReservoirID" FOREIGN KEY ("ReservoirID") REFERENCES "Reservoirs" ("ID") ON DELETE RESTRICT
);


CREATE TABLE "StockLotConsumptions" (
    "ID" integer GENERATED BY DEFAULT AS IDENTITY,
    "StockLotID" integer NOT NULL,
    "PeriodeDetailID" integer NOT NULL,
    "QuantiteConsommee" numeric(12,3) NOT NULL,
    "PrixUnitaire" numeric(10,2) NOT NULL,
    "DateConsommation" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_StockLotConsumptions" PRIMARY KEY ("ID"),
    CONSTRAINT "CK_StockLotConsumptions_PrixUnitaire_NonNegative" CHECK ("PrixUnitaire" >= 0),
    CONSTRAINT "CK_StockLotConsumptions_QuantiteConsommee_Positive" CHECK ("QuantiteConsommee" > 0),
    CONSTRAINT "FK_StockLotConsumptions_PeriodeDetails_PeriodeDetailID" FOREIGN KEY ("PeriodeDetailID") REFERENCES "PeriodeDetails" ("PeriodeDetailID") ON DELETE CASCADE,
    CONSTRAINT "FK_StockLotConsumptions_StockLots_StockLotID" FOREIGN KEY ("StockLotID") REFERENCES "StockLots" ("ID") ON DELETE RESTRICT
);


